{kind="quest",zone="Blade's Edge Mountains",qid=10620,mapID=1949,x=60.4,y=68.8,ox=68,oy=63,omap=1949,band={65,67},quest="Ridgespine Menace",text="Ridgespine Menace",detail="Dizzy Dina wants you to kill 10 Ridgespine Stalkers. After you have done so, return to her at Toshley's Station in the Blade's Edge Mountains.",target="Ridgespine Stalker",races=1101},
