{kind="quest",zone="Blade's Edge Mountains",qid=10675,mapID=1949,x=60.5,y=69,band={65,68},quest="Show Them Gnome Mercy!",text="Show Them Gnome Mercy!",detail="Toshley wants you to retrieve the Collection of Souls and return it to him at Toshley's Station in the Blade's Edge Mountains.",races=1101},
