{kind="quest",zone="Blade's Edge Mountains",qid=10517,mapID=1949,x=44,y=51.8,ox=38.9,oy=48.7,omap=1949,band={65,67},quest="Gorr'Dim, Your Time Has Come...",text="Gorr'Dim, Your Time Has Come...",detail="Vindicator Vuuleen has asked you to kill Gorr'Dim, leader of the Bladespire Hold ogres. Once you have done so, return to her at Bladespire Hold in the Blade's Edge Mountains.",target="Gorr'Dim",races=1101},
{kind="quest",zone="Blade's Edge Mountains",qid=10518,mapID=1949,x=44,y=51.8,tx=36.2,ty=66.2,tmap=1949,band={65,67},quest="Planting the Banner",text="Planting the Banner",detail="Use the Bladespire Banner atop the Northmaul Tower to lure Gurn Grubnosh. Deliver the banner and the Helm of Gurn Grubnosh to Commander Skyshadow at Sylvanaar in the Blade's Edge Mountains.",races=1101},
