{kind="quest",zone="Blade's Edge Mountains",qid=10510,mapID=1949,x=37.4,y=65,band={65,66},quest="Into the Draenethyst Mine",text="Into the Draenethyst Mine",detail="Bronwyn Stouthammer has asked you to collect 5 Draenethyst Mine Crystals and then return to her at Sylvanaar in the Blade's Edge Mountains.",races=1101},
