{kind="quest",zone="Blade's Edge Mountains",qid=10812,mapID=1949,x=62.7,y=40.4,band={65,68},quest="Mystery Mask",text="Mystery Mask",detail="Bring the Mystery Mask to Wildlord Antelarion in Ruuan Weald.",item=31387},
