{kind="quest",zone="Blade's Edge Mountains",qid=11000,mapID=1949,x=55.5,y=44.9,band={70,70},quest="Into the Soulgrinder",text="Into the Soulgrinder",detail="Retrieve Skulloc's Soul and deliver it to Mog'dorg the Wizened atop the tower at the Circle of Blood in the Blade's Edge Mountains.",item=32467},
{kind="quest",zone="Blade's Edge Mountains",qid=10996,mapID=1949,x=55.5,y=44.9,band={70,70},quest="Maggoc's Treasure Chest",text="Maggoc's Treasure Chest",detail="Retrieve Maggoc's Treasure Chest and deliver it to Mog'dorg the Wizened atop the tower at the Circle of Blood in the Blade's Edge Mountains."},
{kind="quest",zone="Blade's Edge Mountains",qid=10989,mapID=1949,x=55.4,y=45.2,band={70,70},quest="Mog'dorg the Wizened",text="Mog'dorg the Wizened",detail="Visit Mog'dorg the Wizened atop the tower where Chort is standing, just outside the Circle of Blood in the Blade's Edge Mountains."},
{kind="quest",zone="Blade's Edge Mountains",qid=11009,mapID=1949,x=55.5,y=44.9,tx=28.8,ty=57.4,tmap=1949,band={70,70},quest="Ogre Heaven",text="Ogre Heaven",detail="Mog'dorg the Wizened has asked you to speak with Chu'a'lor at Ogri'la in the Blade's Edge Mountains."},
{kind="quest",zone="Blade's Edge Mountains",qid=10806,mapID=1949,x=53.3,y=41.2,band={65,70},quest="Showdown",text="Showdown",detail="Use Sablemane's Signet at the Altar of Goc, then kill Goc. Return to Baron Sablemane at the Circle of Blood in the Blade's Edge Mountains when this is done.",target="Goc",item=31808,races=1101},
