{kind="quest",zone="Blade's Edge Mountains",qid=10912,mapID=1949,x=63.2,y=62.5,tx=62.3,ty=40.1,tmap=1949,band={65,68},quest="The Hound-Master",text="The Hound-Master",detail="The Evergrove Druid has told you that the final thing you must do is to slay Baelmon the Hound-Master. Afterward, return to Evergrove in the Blade's Edge Mountains, and inform Wildlord Antelarion of your success.",target="Baelmon the Hound-Master",item=31809},
{kind="quest",zone="Blade's Edge Mountains",qid=10581,mapID=1949,x=55.1,y=72.8,tx=60.5,ty=69,tmap=1949,band={65,67},quest="Follow the Breadcrumbs",text="Follow the Breadcrumbs",detail="In a round-about way, R-3D0 has informed you that if you follow the trail of spare parts up the ramp here to the Razor Ridge, you will find the gnomes at a place named Toshley's Station.",races=1101},
